// rest are adoption-only. Shape matches the reusable dog record in data/dogs.js.
export const sdcDogs = [
  {"id": "sdc-ace", "name": "Ace", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "4 years 3 months", "ageMonths": 51, "dob": "3.2022", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/3c07f5_c966056f27cb412ead9674a5b1d69f19~mv2.jpg"], "personality": "- IN FOSTER - \nDOB 03/2022. Ace is a soft-souled gentleman who was sadly let down by the only family he ever knew. At 4 years old, being left behind has taken its toll on him, but he is bravely rediscovering his confidence and is so ready to swap the boarding kennel for a real home again.\nWe are looking for a stable, loving foster family (or even better, a forever family!) who can give Ace the sanctuary he needs to fully come out of his shell and heal his heart.\n✨ Why Ace is the Perfect Foster Guest:\n- True Gentleman: Naturally friendly with every person he meets.\n- Dog Social: He plays beautifully with his dog pals and loves making new friends.\n- Low Maintenance: A calm, regular-sized Husky with a very gentle temperament.\n- Ready to Move: He is neutered, fully vaccinated, and eager for a sofa.\nAce just needs a little bit of patience and a lot of love to let his true personality shine through. If you have a corner of your home and a spot in your heart for a dog who just wants to belong, Ace is waiting for you.\n➡️ Ready to be Ace’s safe haven? Apply to FOSTER or ADOPT today:"},
  {"id": "sdc-alfie", "name": "Alfie", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "5 years 1 month", "ageMonths": 61, "dob": "5.2021", "shelterId": "sdc-uaq", "availableFor": "adoption", "photos": ["https://static.wixstatic.com/media/3c07f5_ca056eab82774a57b9d60fc134189225~mv2.jpeg"]},
  {"id": "sdc-andre", "name": "Andre", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "1 year 10 months", "ageMonths": 22, "dob": "8.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/3c07f5_8f3db2297a0548f18991da206bf929de~mv2.jpg"], "personality": "This handsome dude has his paws crossed🤞🏼hoping to find a new foster home soon. A young boy, born 08/2024 , André is fully vaccinated ✔️ \nand fully grown, he’s on the smaller side of medium.\nHe has been house trained, walks on leash like a champ, is toilet trained and fine alone for a few hours 😇\nWith his pointy ears, pointy nose 😅 and unique coloured coat 🩶🤍🩶, Andre is quite the looker 😁\nA friendly little soul, he gets along well with dogs (on leash, on walks and also off leash in dog parks and daycare).\nAnd whilst he’s a little shy with new people, all it takes is some tasty treats and a bit of patience to win him over 😋 \nAndré would make for a great addition to any home; either as an only pet or as one of many! André is hoping, as are we, that he finds his forever home soon 🙏🏼🤞🏼\nBut for now needs to find a new place to lay his head for a while."},
  {"id": "sdc-angel", "name": "Angel", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years", "ageMonths": 24, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/3c07f5_3b0d799838fc4d28a94f3d50747c4f64~mv2.jpeg"], "personality": "- IN FOSTER -\nFound wandering alone in DIP, this beautiful girl was given a second chance when she moved into our 'Boster' programme. Angel has been decompressing at Bed & Biscuits, and we are so proud of the progress she is making!\n✨ Why Angel is a True Blessing:\n- Quick to Wag: She has a heart full of gratitude and hope and is always ready to wag for a kind word.\n- Snack Queen: Angel absolutely loves her treats - it’s the quickest way to her heart!\n- Sweet & Gentle: After a few quiet days, she is already seeking out gentle strokes and human connection.\n- Health Ready: At around 2 years old, she is at a perfect age to settle into a new life.\n🏠 What Angel Needs to Blossom:\n- Angel is looking for a sanctuary where she can leave her wandering days behind for good.\n- A Calm Sanctuary: She needs a quiet, low-stress home environment where she can continue to decompress.\n- Patience & Love: She is looking for someone to help her fully emerge from her shell at her own pace.\n- A Soft Landing: After her time on the streets, a comfy bed and a predictable routine are her biggest dreams.\nAngel is making incredible progress and is now officially ready to move into a loving home environment. If you have a peaceful home and a love for an elegant, gentle soul, Angel is waiting to be your most devoted companion."},
  {"id": "sdc-apollo", "name": "Apollo", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 2 months", "ageMonths": 26, "dob": "4.2024", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "photos": ["https://static.wixstatic.com/media/1ababb_17054f0e295b4d328f277587343eb571~mv2.jpg"], "personality": "Aptly named after the Greek God of music 🎶 and dance🕺🏻, this gorgeous young dog is ready to fill your life with fun and joy!\nApollo is a young boy (born 4/2024) and is fully vaccinated ✔️ \nWith his striking eyebrows and masked face 🐼, this youngster is a beauty 🤩\nOhhh and he has a nose that’s just made to be booped 😂\nA friendly soul, he gets along well with people and dogs 🐕 \nAnd enjoys cuddles 🤗\nApollo is also available for adoption🤞🏼\nWould you like to meet Apollo?!\nFill our application today!"},
  {"id": "sdc-apple", "name": "Apple", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_c0bd634aff2c4d4290651ecb22bec9f6~mv2.jpg"], "personality": "Meet Apple!\nApple can be a little timid at first and finds the outside world pretty scary but in a home, his sweet nature and happy soul shine through.\nPetite, neutered and fully vaccinated, this sweet boy would do well in any sized patient home.\nCan you be the one to show apple that the world is not so scary after all?"},
  {"id": "sdc-austin", "name": "Austin", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "4 years", "ageMonths": 48, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/1ababb_a1cbc5220ff3461492447de438ee4e21~mv2.jpg"], "personality": "- IN FOSTER - \nAustin is a lovely boy, who recently joined our doggies in boarding. He  is about 4 years old and a laid-back boy. He’s good with other dogs, adores people. He loves going on walks and is well behaved on the leash. He's easy going and loves belly rubs. \nCan you open your house to our Texas boy, Austin? 🤠🤎 Please fill either application form and mention Austin!"},
  {"id": "sdc-badger", "name": "Badger", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_cf832360994642e6927118493c195bf8~mv2.jpg"], "personality": "This handsome heart-melter has been waiting patiently to start his forever. \nBadger may look like a shy, well-mannered little gentleman (the kind who would say “excuse me” before taking a treat), but once he settles in, get ready for full-on goofy, zoomie-loving puppy energy! When he first arrived, Badger was a tiny, underweight bean, but thanks to some TLC (and plenty of snacks), he’s blossomed into a happy, playful pup.\nHe’s neutered, fully vaccinated, and has lived in a home before. He just needs another chance to feel safe and loved. Are you ready for both cuddles and funny chaos?"},
  {"id": "sdc-bagel", "name": "Bagel", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "5 years", "ageMonths": 60, "dob": null, "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/1ababb_14c95a2cf6c8419b9c51161e3bfcc164~mv2.jpeg"], "personality": "Beautiful Bagel is still waiting for his special forever home🤞🏼\nFound with a severely injured leg which led to amputation, this tripaw warrior has been through a lot and proven himself to be a strong and resilient lad 💪🏼 \nBagel is around 5 years of age, fully vaccinated and neutered ✔️ \nHe gets along with other dogs but does feel overwhelmed on leash and has been undergoing training on this.\nBeing a smart boy, he’s quick on the take and very trainable 😇\nWe believe Bagel would be better suited to a home with a garden.\nAfter what he’s been through, Bagel so deserves the comforts of a home 🥹"},
  {"id": "sdc-bailey", "name": "Bailey", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "4 years", "ageMonths": 48, "dob": "6.2022", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "photos": ["https://static.wixstatic.com/media/3c07f5_176b5de7150445158b120517a4b06c0f~mv2.jpeg"], "personality": "- IN FOSTER - \nMeet the Radiant Bailey! 🐾\nIf you are looking for a dog who will greet you like a hero every single day, look no further than Bailey. This 3.5-year-old charismatic girl is the definition of pure joy (DOB 06/2022). With her \"boundless wags\" and a spirit that seems to run on sunshine, Bailey is officially ready to start her life over with a family to call her own.\n✨ Why Bailey is a Total Heart-Stealer:\n- Boundless Wags: Bailey doesn’t just wag her tail; she wags her entire soul! She is a vibrant presence who is genuinely thrilled to see you every time you walk through the door.\n- A New Chapter: Beautiful Bailey was rescued with her puppies and has been the most devoted mama. Now that her babies are busy finding their own families, she can finally focus on her own future and be the one who is pampered.\n- The Ultimate Socialite: Perfectly friendly with all \"floofs\" and a total people-lover, Bailey is a social butterfly who brings harmony and happiness wherever she goes.\n- Sweet & Refined: At 3.5 years old, she has reached that perfect age - past the puppy chaos and ready for a tranquil life of steady walks and sofa snuggles.\n📋 The Details:\n- Age: 3.5 Years Old.\n- Personality: Consistently happy, social, and incredibly gentle.\n- Health: Fully vaccinated and ready for her fresh start.\n- Vibe: An exquisite companion who is ready to be your most loyal best friend.\nBailey has done so much for others; now she is looking for her own \"people\" to help her write her next chapter. Can you be the ones to give her the beautiful future she deserves?\n➡️ Ready to be on the receiving end of those boundless wags? Apply today"},
  {"id": "sdc-barney", "name": "Barney", "gender": "Male", "breed": "Malinois X", "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 1 month", "ageMonths": 37, "dob": "5.2023", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/1ababb_e220f296e17d4cf9af435ccddb361599~mv2.jpg"], "personality": "Meet Barney, our handsome young boy, born 5/2023 🩵\nBarney is quite shy to start with, but as he builds the trust, you will find a loving, friendly chap.\nHe is pretty confident around other dogs too and he likes to spend time with humans. He will be a wonderful addition to a loving family and he would be happy to join another dog in his future home. \nWe would love to find a foster home for him while searching for adopters.\nPlease PM or click on the link below to fill our application if you wish to meet Barney 💙"},
  {"id": "sdc-baxter", "name": "Baxter", "gender": "Male", "breed": "Malinois X", "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 6 months", "ageMonths": 30, "dob": null, "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_f4d1b3359c1446f9a512f5e3af9be25e~mv2.jpg"], "personality": "Baxter was adopted from us as a puppy, and after two years in a home we thought was loving, he was heartbrokenly surrendered to the shelter.\nIf you've ever wondered what a broken heart looks like, just look into Baxter's beautiful brown eyes. He is sweet but heartbreakingly unsure. He doesn't know where his people are, and he has one eye on the door, waiting for them to return.\nWhen a dog is surrendered, it completely rocks their foundation. Baxter needs a true hero -someone who can show him that a safe, forever life is waiting for him.\n🌟 About Baxter:\n•⁠  ⁠Age: 2.5 years old \n•⁠  ⁠Size: Medium-sized boy.\n•⁠  ⁠Health: Fully vaccinated and neutered.\n•⁠  ⁠Needs: Daily walks and a proper diet to help him reach his ideal weight. Most importantly: patience, consistency, and a lifetime of commitment.\nAre you ready to be the one to restore Baxter's faith in people? We promise that the loyalty you receive in return will be immeasurable. Fill out the adoption application and be sure to mention Baxter!"},
  {"id": "sdc-bean", "name": "Bean", "gender": "Male", "breed": "Malinois X", "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 1 month", "ageMonths": 37, "dob": "5.2023", "shelterId": "sdc-uaq", "availableFor": "both", "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_e8e9b166d7a6411b8c977c5364d1f053~mv2.jpg"], "personality": "Meet Bean, a cheerful and friendly young boy. Born 5/2023, neutered and full of beans (pun intended) 😁 He is a lively and energetic boy and he is looking for a home to call his own 🏡 Bean is available for adoption but since he is living in boarding, a temporary foster home will be very welcome too 🙏\nPlease message us or fill out the application form if you would like to meet Bean."},
  {"id": "sdc-bea", "name": "Bea", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 8 months", "ageMonths": 32, "dob": "10.2023", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_cabad71ebb1c46cf86234fd9ce138c01~mv2.jpg"], "personality": "DOB 10/2023. If you’re looking for a dog who treats every single morning like a celebration, meet Bea. At 2.5 years old, this stunning Husky doesn’t just live life - she embraces it with an infectious \"lust for life\" that turns every walk into an adventure!\n✨ Why Bea is Pure Sunshine:\n- High Energy: Bea treats every day like it's the best one yet.\n- City Chic: Surprisingly unbothered by the hustle and bustle of busy areas.\n- Friendly Explorer: Once settled, she’s a calm, easy-going partner who loves to sniff and discover.\n- Health Ready: Spayed, fully vaccinated, and ready to find her teammate.\nBecause we aren’t sure of her past home-life experience, Bea will need a a little help to learn the \"house rules\" and some consistent guidance to channel her beautiful spirit. If you’re ready for a high-energy partner to make every day a win, Bea is waiting for you!\n➡️ Ready to keep up with Bea? Apply to foster or adopt today:"},
  {"id": "sdc-beau", "name": "Beau", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "senior", "ageLabel": "8 years", "ageMonths": 96, "dob": null, "shelterId": "sdc-uaq", "availableFor": "adoption", "photos": ["https://static.wixstatic.com/media/3c07f5_e1631a865e8246b7b02dd163085e8751~mv2.jpg"], "personality": "Beau is proof that old souls shine the brightest ✨  \nWith his silver whiskers and gentle eyes, this 8-year-old gentleman carries a lifetime of love in his heart.\nAfter years in the shelter, he's now got a chance to find a home and has found a spot in our boster program.\nHe dreams of the perfect day....cuddles on the couch, long naps, short strolls, and curling up to watch Netflix with his family ❤️\nHe’s not asking for adventures. Just a soft bed, a kind hand, and someone to share his evenings with.  \nIf your home has room for a loyal shadow and the world’s best TV buddy, Beau is waiting for you.\nCan you open your heart and home to this lovely boy? Even for a short time 🤞"},
  {"id": "sdc-bear", "name": "Bear", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_4ee04d4583c34ce8ab58b2bd07eee3c1~mv2.jpg"], "personality": "Bear is searching for his Adoption Home 💙🐻\nThis handsome boy is full of energy, love, and character 🤩 He was rescued with his sister from an abandoned villa, and despite his rough start, Bear’s spirit is nothing but joyful and affectionate 🌟 \nBear recently got the chance at a short term foster and he was an absolute super star! He’s clever, playful, and loves being part of the action! 🥳🥎\nBear is still learning some manners when out and about 🐾, but with patience and training, he’s going to grow into the best adventure buddy ever 🙌🏻\n✅ Fully vaccinated\n✅ Neutered\n✅ Smart, funny, and oh-so-loving 🥰\nNow all Bear needs is a family who’ll give him the guidance and love he deserves 🏡 Whether it’s a short stay or forever, you’ll be rewarded with zoomies, cuddles, and endless puppy smiles 💛\nCould Bear be your new best friend?"},
  {"id": "sdc-bella", "name": "Bella", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 5 months", "ageMonths": 41, "dob": "1.2023", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": false, "photos": ["https://static.wixstatic.com/media/3c07f5_53cb42097ed74026b32c20dbde2f45a5~mv2.jpg"], "personality": "DOB 01/2023. This gorgeous husky girl is one of our recent recruits from the center,  who has come to boarding in Dubai in the hopes of being spotted and finding a home 🤞\nBella is 3 years of age and fully vaccinated ✔️ \nShe is a medium size girl who is an extremely friendly, playful and social doggo 🥰\nBella is loving life in boarding, after spending the past year at our center. She is making sure to greet all she meets, people and other dogs, with her natural charm 😊\nBella is looking for a home, even a temporary one for now would be great 🙏🏼 So we can arrange for her spay and she can then recover in the comforts of a home 🥹\nBella is also available for adoption🤞🏼both in the UAE, and overseas as part of our Husky Relocation Mission."},
  {"id": "sdc-bella-2", "name": "Bella", "gender": "Female", "breed": "Italian Greyhound", "size": null, "sizeLabel": null, "ageGroup": "young", "ageLabel": "1 year 3 months", "ageMonths": 15, "dob": "3.2025", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_78f7514c79e340faad038794866fdf1e~mv2.jpeg"], "personality": "- IN TRIAL ADOPTION - \nDOB 03/2025. MEET BELLA: PURE JOY IN A DINKY DOG FORM! 🐾\nIf you are looking for a pocket-sized bundle of happiness, look no further than the exquisite Bella! At just over 1 year old, this stunning Italian Greyhound is the definition of grace, fun, and compact affection.\nRecently surrendered by her owner through no fault of her own, Bella is healthy, fully vaccinated, spayed, and completely ready to find her true forever family. \nThe Quick Facts:\n- Age & Breed: Just over 1 year old, Italian Greyhound.\n- Status: Spayed, fully vaccinated, and healthy.\n- Vibe: Playful, exceptionally friendly, and a total sweetheart.\n- Size: Petite, elegant, and perfectly \"dinky!\"\nWhy Bella is a Total Dream Housemate:\n- Crate Trained Pro: Bella has already mastered her crate training, making her transition into a new home routine so much easier.\n- Independent Streak: She is perfectly fine being left alone for a few hours, meaning she handles a normal daily schedule like an absolute champ.\n- Social & Playful: She has a beautifully friendly nature, bringing a vibrant spark of joy and playfulness wherever she goes.\nHer Ideal Match:\nBella is looking for a loving home that appreciates the sensitive, affectionate, and active nature of the Italian Greyhound breed. Whether you are looking for a walking companion or a professional snuggle partner for the sofa, Bella is ready to fill your life with love.\nReady to welcome this dinky bundle of joy into your life?"},
  {"id": "sdc-bentley", "name": "Bentley", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years", "ageMonths": 36, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": false, "photos": ["https://static.wixstatic.com/media/3c07f5_6a2e49a340a349e6b239ed0895331edc~mv2.jpg"], "personality": "- IN FOSTER - \nTHE PETITE PRINCE: Bentley is Ready for His Forever! 🐾\nIf you have a heart for the sensitive souls, meet Bentley. At 3 years old, this petite Italian Greyhound is looking for a gentle landing spot where he can truly feel secure. Like many of his breed, Bentley is a delicate boy who navigates the world with a bit of caution, but he has so much love to offer the right person.\n✨ Why Bentley is a Rare Find:\n* Classic Charm: Elegant, petite, and a true 3-year-old gentleman.\n* Building His Brave: A shy boy who needs a patient anchor to find his confidence.\n* Gentle Soul: Best suited for a calm environment where he can feel safe.\n* Health Ready: Fully vaccinated and will be neutered soon.\n* \nBentley isn't looking for a high-energy household - he's looking for a soulmate who understands that trust is earned with soft words and quiet moments. If you have a peaceful home and a love for Italian Greyhounds, Bentley might be the perfect match for you."},
  {"id": "sdc-bibi", "name": "Bibi", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 4 months", "ageMonths": 28, "dob": "2.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_9b8fa29cac2945138d970752e14a1626~mv2.jpg"], "personality": "- IN FOSTER -\nThis little sweetheart is looking for a temporary place to crash while her foster fam travels in August!\nMeet Bibi, a total cuddle bug, obsessed with belly rubs, and she will follow you around like your fluffy little shadow 💖😁 Bonus? Bibi is cat crazy, in the best way! She loves to play, snuggle, and hang out with feline friends 🐾🐱\nShe’s been in a loving foster home and has blossomed beautifully 🌸🌻 She loves going on walks and hunting little insects in the bushes 🤭 She is also a big fan of treats and will smack on them with a lot sound 😂 \nBibi is a young lady (born 2/2024), spayed, vaccinated, and ready to steal your heart (and your spot on the couch 💁‍♀️).\n📩 Fill in the application if you want to meet this loving girl!"},
  {"id": "sdc-billy", "name": "Billy", "gender": "Male", "breed": "short legged mix", "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 3 months", "ageMonths": 27, "dob": "3.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": false, "photos": ["https://static.wixstatic.com/media/1ababb_0e18cc353a0d45dfa4923d435df47dc9~mv2.jpg"], "personality": "- IN FOSTER -\nDOB 03/2024. Billy is a bundle of joy, small in size but big in personality 🐾 With his adorable mix of breeds and constant happy grin, he’s impossible to resist 🐶💛 He loves strolling through gardens and parks, always in “explore mode” with his tail wagging 🏞️\nSweet and affectionate, Billy is the kind of pup who makes everyone feel special 💙 He’s fully vaccinated and soon to be neutered, ready for the next step in his journey! All he’s missing now is a loving home to call his own 🏡\nCould you be the one to give this cheerful little chap a soft place to land, and the love he deserves? \nFill our adoption application today and mention Billy! Our team will then reach out."},
  {"id": "sdc-bobby", "name": "Bobby", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "4 years", "ageMonths": 48, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_61f0feaffd1e400b9b2f6658cb149908~mv2.png"], "personality": "Our Bobby boi is looking for a foster home 🥹\nOf course,  a forever home would be even better🤞🏼\nBobby is around 4 years of age, fully vaccinated and neutered ✔️ \nA very shy boy, we’re so hoping Bobby gets a chance to move into a home where he can build his self confidence and know love and affection ☺️\nAnother calm and confident doggy would be an added bonus as Bobby does feel comfortable around other dogs 🐶 \nA patient and understanding approach would do wonders for Bobby 🙏🏼\nPlease don’t overlook the shy ones…they deserve their chance too!"},
  {"id": "sdc-bubbles", "name": "Bubbles", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years", "ageMonths": 36, "dob": "6.2023", "shelterId": "sdc-uaq", "availableFor": "adoption", "photos": ["https://static.wixstatic.com/media/3c07f5_39407000be8144259712b711827a0d53~mv2.jpeg"]},
  {"id": "sdc-casper", "name": "Casper", "gender": "Male", "breed": "Border Collie", "size": null, "sizeLabel": null, "ageGroup": "senior", "ageLabel": "8 years 8 months", "ageMonths": 104, "dob": "10.2017", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_437d73db84454a61a3184fcd26e3cc9d~mv2.jpg"], "personality": "Meet Casper, a stunning 8.5 year-old Border Collie who was cruelly left at the vets!Abandoned by his owners who never even asked how he was doing! \nHe now needs an active loving foster or forever family to show him that not all humans are bad! \nWe are looking for an experienced home for this amazing boy so that he can move out of boarding asap and continue his journey.\nHe is extremely smart and highly focused, making him a dream dog for the right person. He is geeat with all people he meets, and other dogs.\nIf you are ready for him and to reap the rewards of a lovely dog, Casper is ready to be your co-pilot and new friend.\n✅ Quick Facts:\n• Breed: Border Collie\n• DOB 10/2017\n• Health: Fully vaccinated and neutered \nReady to give this genius boy the new start in life he deserves?\nTo foster or adopt Casper, apply now!"},
  {"id": "sdc-chelsea", "name": "Chelsea", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 3 months", "ageMonths": 39, "dob": "3.2023", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/1ababb_88d34fde04f04a1981b82c8a455e1821~mv2.jpeg"], "personality": "- IN FOSTER -\nMiss Chelsea is a lovely desert mix waiting for her forever home🤞🏼\nShe is young (born 3/2023) and a sweet little girl 🥰\nPlease fill the application now and mention Chelsea ❤️"},
  {"id": "sdc-cherry", "name": "Cherry", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/1ababb_6f689de262264e1d98a73fde581cdd24~mv2.jpg"], "personality": "Our beautiful girl Cherry is thriving in Dogwalk boarding.\nWe would really love a foster home for her as \nshe is such a wonderful dog, and the victim of human abuse. She was hit by a car and left to die by a roadside. With physiotherapy and a set of wheels, she's enjoying her life in boarding, but a home is where she deserves to be.\nShe's been failed in the past, let us not fail her ever again 🙏\nPlease send us a message if you would like to know more 🙏"},
  {"id": "sdc-coffee", "name": "Coffee", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "young", "ageLabel": "1 year 5 months", "ageMonths": 17, "dob": "1.2025", "shelterId": "sdc-uaq", "availableFor": "adoption", "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/3c07f5_5f698d31cfd447b5b310636bb6826ded~mv2.jpg"], "personality": "DOB 01/2025. Coffee may be a little shy when you first meet him, but like his name suggests he is sweet and full of character 😘\nOnce he has had a little time to get to know you, he quickly shows his gentle and affectionate side.\nHe is a lovely young pup with plenty of personality and, with patience and kindness, he will grow in confidence and become a loyal companion.\nCoffee loves ear scratches and often rests his head against yours when he wants a little affection. He is great with other dogs and enjoys socialising and playing with his canine friends."},
  {"id": "sdc-cooper", "name": "Cooper", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "4 years 5 months", "ageMonths": 53, "dob": "2022", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "goodWithKids": false, "photos": ["https://static.wixstatic.com/media/1ababb_5b05f11a21ea4a788bc93f52fceb2d2e~mv2.jpg"], "personality": "Cooper needs out of the kennels!!!\nThis poor boy is yet another sad case of surrender 😔\nAdopted as a puppy and now returned 😢\nCooper is a young adult (born 2022) and is fully vaccinated and neutered ✔️ \nCurrently in boarding in Dubai, he is sad and confused, wondering why he’s not in his home surrounded by the only people he knew as family 🥺\nCooper needs a dog experienced, adult only household who can work on his training 🙏🏼\nIn boarding, he gets along with the other dogs and the staff there 😊\nAnd at a recent adoption day he attended, Cooper did well with all the other dogs and those that attended 😊\nCould someone please offer this boy a chance?! 🙏🏼\nFill our application and remember to mention Cooper 💙"},
  {"id": "sdc-dingo", "name": "Dingo", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "senior", "ageLabel": "8 years", "ageMonths": 96, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_1f6b0bf31b5040d693e7958aaafe385c~mv2.jpg"], "personality": "- IN FOSTER -\nSPECIAL SENIOR: Meet Dingo! this older boy needs a foster home 💙\nAfter spending the past few years at the shelter going unnoticed 😪 we decided it was time to give him shot at finding a place to rest his head 🤞\nWith his stunning looks, he's quite the distinguished gentleman 🥰\nIf you’re looking for a boy who’ll melt your heart, this one of them! \nDingo is 8 years old and honestly, he’s the ultimate ladies’ man 🥰 and man's man 💪  Obsessed with cuddles, always smiling, always wagging that gorgeous tail. He’s one of those dogs who you can imagine snoozing at your feet, following you around the house, or curling up beside you on the sofa 😴\nHe’s medium-sized, mixed breed, who is gentle, affectionate, and so ready to finally experience what a real home feels like after so long .....A soft bed, with kind people, feeling safe and loved 🥰 He’s waited long enough ❤️\nCould you be his fresh start, even for a short term? \nHe will need a little support at the start from you, but what you'll get back will be so much more 🥰🥰🥰\nDingo is fully vaccinated and neutered. \nIf you can offer Dingo a foster home — even just short-term — please reach out. This boy has so much love to give 🥰"},
  {"id": "sdc-dion", "name": "Dion", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 2 months", "ageMonths": 26, "dob": "4.2024", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/1ababb_678944db86bc4717aa3cc5a969a53952~mv2.jpg"], "personality": "- IN FOSTER -\nDion is an identical twin with his sister Orchid and both are looking for homes (foster or even better - forever homes) 🤞🤞\nThese adorable brother and sister are still playful youngsters (born 4/2024). They are comfortable in the company of other doggies, and friendly with new people 😇. They are young and smart,  and they would be happy to learn house rules very fast 👍🏼\nWith their beautiful markings and long saluki shaped bodies, they will steal your heart ❤️ Please fill our application to meet them!"},
  {"id": "sdc-dolly", "name": "Dolly", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "7 years 2 months", "ageMonths": 86, "dob": "4.2019", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/3c07f5_e268d29c0e31431fa1278c2556dd092b~mv2.jpg"], "personality": "- IN FOSTER - \nDOB 04/2019. If you are looking for an easygoing, loving companion to bring a sense of peace to your home, meet beautiful Dolly. She is the definition of a gentle soul and is ready to find her perfect match.\nThe Details:\nVibe: Easygoing, warm, and incredibly friendly.\nSkills: Walks beautifully on the lead.\nNature: Gentle and patient.\nLoves: A good cuddle and being close to her people.\nWhy She’s The One:\nDolly is the kind of dog who fits right into your life with ease. She is a friendly girl who handles her walks like a total professional, making every outing a pleasure. Whether you are looking for a partner for a calm stroll or a companion to snuggle with on the sofa, Dolly's warm presence makes her the ideal addition to any home."},
  {"id": "sdc-dougie", "name": "Dougie", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "5 years 3 months", "ageMonths": 63, "dob": "3.2021", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/3c07f5_25e7c3e1c8214896bbfd0f2c4bc06ff3~mv2.jpeg"], "personality": "- IN FOSTER - \nDOB 03/2021. Dougie joined our Boster programme from the shelter and has been absolutely amazing in his recent foster home. He has proven himself to be the ultimate house dog, completely ready for a permanent spot on a sofa of his own 😇😇😇\nThe Quick Facts:\n- Vibe: Easygoing, friendly with everyone, and incredibly loving.\n- Manners: A brilliant house dog who is calm and content.\n- Special Move: Greets you with the wiggliest, happiest tail wags when you walk through the door.\nWhat Dougie Needs:\nDougie is content to spend his day chilling on the couch until his people come home. He is looking for a steady, loving environment where he can finally relax and know that his place on the sofa - and in your heart - is safe forever."},
  {"id": "sdc-duke", "name": "Duke", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/1ababb_64187239bc594c66a5e904ddb2e31737~mv2.jpeg"], "personality": "- IN FOSTER - \nMeet Duke, the masked gentleman with a golden heart.\nWith his unique masked eyes, Duke looks like he’s always ready for a masquerade ball… though, on the side, he could probably pass as a member of the band KISS 🎸.\nBorn in February 2021, Duke has spent most of his life waiting — first at the shelter, then ages in boarding — constantly overlooked because of his striking appearance. It’s heartbreaking, because once he gets to know you, he’s pure sweetness and devotion.\nA little shy at first, Duke quickly warms up and loves being close to his people. He’s well-socialised with other dogs and would thrive in a calm, caring home where he can finally be part of a family.\n🐾 Duke has waited long enough. Could you be the one to see the real him behind his mask?\nStart by filling the foster/adoption application and our team will be in touch!"},
  {"id": "sdc-freddie", "name": "Freddie", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 2 months", "ageMonths": 38, "dob": "4.2023", "shelterId": "sdc-uaq", "availableFor": "both", "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_e5c3bed753e4476192d5428aa03342d3~mv2.jpg"], "personality": "DOB 04/2023. If you've been searching for a gentle, easygoing companion to complete your family, Freddie could be the one!\n3-year-old Freddie is neutered, thriving in foster care, and showing everyone what a fantastic dog he is. With his classic Labrador-type personality, he's sweet, calm, and incredibly easy to have around.\n✨ The Quick Facts:\n* Neutered\n* Living with a child and doing amazingly\n* Gentle, affectionate, and easygoing\n* Settled beautifully into home life\nWhy Freddie is So Special:\n🐾 Family-Friendly – Freddie is currently living with a child and has proven himself to be patient, loving, and the perfect family companion.\n🐾 Easygoing Nature – He takes everything in his stride and has adapted wonderfully to home routines.\n🐾 Loyal & Loving – Freddie simply wants to be part of the family and share life's everyday moments with his people.\nFreddie was found wandering alone, but those days are behind him. Now all he needs is a forever family to call his own."},
  {"id": "sdc-gracie", "name": "Gracie", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "4 years", "ageMonths": 48, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/1ababb_577e5a7ca79d4e0db11cdb0654b4bf09~mv2.jpeg"], "personality": "Gracie Is Ready for a Home 🐾\nDon’t let her time in the shelter or boarding fool you — this gentle girl is a natural at living her best life. Thanks to a wonderful foster sponsor, Gracie has spent weekends out and about, showing off her loving personality and excellent manners.\n🚗 She’s a calm, happy passenger on car rides and always up for a little adventure.\n🐶 Wherever she goes, she wins hearts with her gentle tail wags and easygoing nature.\n🏡 Indoors, Gracie is relaxed, well-behaved, and an absolute joy to have around — the perfect companion.\nAt about 4 years old, Gracie is still full of love and life — ready to settle into a home where she can truly shine. 💛\nWe know there’s a lucky family out there ready to welcome this wonderful dog into their hearts and home. Could it be yours?\nDon’t miss your chance to make Gracie part of your story — her happily-ever-after is waiting! 🐶✨"},
  {"id": "sdc-greta", "name": "Greta", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "1 year 11 months", "ageMonths": 23, "dob": "7.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_fababe67183f4181948d37fb14dadbf4~mv2.jpeg"], "personality": "- IN FOSTER - \nDOB 07/2024. GRETA:  CHOSEN FOR A BETTER LIFE 🐾\nShe now needs a foster home to help her on her journey 🙏\nSome dogs simply steal your heart and Greta is one of them ❤️ She is waiting for the quiet, loving home she truly deserves.\nThe Quick Facts:\n- Vibe: Sweet, quiet, and reserved.\n- Ideal Home: A calm, predictable, and peaceful environment.\nWhat Greta Needs:\n- A Quiet Sanctuary: Because she is naturally reserved, she thrives in low-traffic settings without too much hustle and bustle.\n- Patience & Love: Greta is looking for a family willing to lead with soft words and let her build trust entirely at her own pace.\n- Time to Trust: She needs a gentle guide to show her that the world is a safe place and that she never has to worry about the streets again.\nCan you offer this gentle girl the peaceful space she needs to blossom?\nGreta is fully vaccinated and spayed.\nShe's a very easygoing girl and would be no bother!\nPlease open your heart and home to this beauty"},
  {"id": "sdc-haven", "name": "Haven", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "young", "ageLabel": "1 year 4 months", "ageMonths": 16, "dob": "2.2025", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/3c07f5_55b723dd69984ee9b59725d768270525~mv2.jpg"], "personality": "DOB 02/2025 this sweet girl is gentle, funny and extremely smart 🥰\nHaven is a quiet little beauty who loves being near her people, soaking up the attention and showing off her world-class puppy skills. 💛 \nShe's wonderful with other dogs too!\n🌸 For Foster / Adoption 🌸\n-------------------------------\nHaven is fully vaccinated and ready for her next big adventure: a foster home, or even better, a forever family 🏡  \nCould Haven  be the one to fill your home with soft puppy love and puppy madness 🥰"},
  {"id": "sdc-hugo", "name": "Hugo", "gender": "Male", "breed": "Labrador Mix", "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "adoption", "photos": ["https://static.wixstatic.com/media/3c07f5_8b12c01bd8404b8386fb3bfe446a8da6~mv2.jpeg"]},
  {"id": "sdc-ice", "name": "Ice", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_b68f5be15f66400b9e2574e131a711d7~mv2.jpg"], "personality": "Meet Ice, a tiny bundle of love who just needs a safe place to land 🐶✨ He’s a little shy at first, and weary of people 🤍, but once he feels secure, his true colors come out: happy zoomies around the house 🏡💨, snuggles in his cozy bed 🛏️, and endless playtime with his toys 🎾🧸\nIce is two years young, fully grown, neutered, and vaccinated 💉 He’s also a great little walking buddy 🚶‍♀️🐕 always ready to trot along by your side.\nAll he needs now is a loving foster home 💕 where he can build his confidence and feel safe.\n📍 Can you open your heart and home to Ice, even just for a while?\nHe’s waiting for his chance… and he needs it now 🙏🏻🐾\nFill in the online application  for Ice"},
  {"id": "sdc-indigo", "name": "Indigo", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "young", "ageLabel": "1 year 3 months", "ageMonths": 15, "dob": "3.2025", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": false, "photos": ["https://static.wixstatic.com/media/3c07f5_b45740c7e87046d6aa521be33267143e~mv2.jpg"], "personality": "- IN FOSTER - \nDOB 03/2025. Meet Indigo: From Shadows to Spotlight 🎬🍿\nWhen Indigo first arrived in Dubai, she was quiet. Her sleek black coat blended into the background 👀\nShe started changing and opening up 🐣 She even got invited to the event at Hotel Indigo Dubai after just a few days in Dubai. As she didn't have a name, it was suitable to name her after one of our sponsors Indigo! 🌟🌻  \nIndigo showed us that behind her silky black coat was a pup ready to live, love, and be seen 🌼🤩 She is now showing off her sassy, playful side. From shy to star 🌟\nIndigo is:\n💉 Fully vaccinated\n❌ Not yet spayed\n😍 Sweet, sassy, and curious\n🖤 Stunning with her velvet-black coat\nShe’s ready for a forever home that sees how special she is. Could that be you?\n👉🏼 Fill out the application to adopt"},
  {"id": "sdc-iris", "name": "Iris", "gender": "Female", "breed": "Labrador", "size": null, "sizeLabel": null, "ageGroup": "senior", "ageLabel": "8 years 8 months", "ageMonths": 104, "dob": "10.2017", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_4244617ae59942be9a88af3457fce70c~mv2.png"], "personality": "SPECIAL SENIOR. \nDOB 10/2017. Iris is a very friendly and happy go lucky gal 🥰. Don't let her birth date of 2017 fool you, this special lady is full of play and ready to live he best life.\nYou’ll be her best friend if you play fetch with her as she enjoys chasing and retrieving the ball 🎾 \nWhich makes us think there could be some Labrador in her 🤔 a \"labsky\" mix 😉. \nAnd she has duo toned eyes 👀 which hints at some Husky in her too 😅\nAll in all, an interesting mix!\nIris had been in a home before and enjoying the good life…perhaps a tad bit too much 😜\nSo a home with a regular exercise routine and regulated meals would help this beauty get back on track with her weight. Strong at first when she gets out on a walk once she gets over the initial excitement of an outing, she's an easy companion. She is fully vaccinated and spayed."},
  {"id": "sdc-isa", "name": "Isa", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 4 months", "ageMonths": 28, "dob": "2.2024", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_1f580beafdac4bd78ce7378ec916c33c~mv2.jpg"], "personality": "DOB 02/2024. Isa here! Just a sweet little lady looking for a comfy couch to call my own 💛 I’m still young (born 2/24), spayed, vaccinated, and full of love to give 🥰 I’ve been staying at Bed&Biscuits boarding, and while my furry friends keep me company, I dream of soft beds, belly rubs, and someone to call my hooman 🛋️✨\nAt first I might seem a little shy but give me a moment and you'll see the real me! Zooming around with my doggy buddies, ears flapping, tail wagging, and a big goofy smile on my face 🎾🐕💕\nI’m a clever cookie 🍪 I pick things up fast and love figuring out how this whole “home life” thing works. Especially if there are treats involved 😋\nWhat I really need right now is someone to show me love, kindness, and a place to stretch out and relax 🌞 Can you help me out? Even just for a few weeks? I promise I’ll be the sweetest little houseguest you’ve ever had 🐾💤\nReady to meet me? Fill in the form and don’t forget to say it’s for Isa 👉"},
  {"id": "sdc-jimmy", "name": "Jimmy", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "1 year 10 months", "ageMonths": 22, "dob": "8.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_a4e9164e03f84c21b7b8edf041fb81d6~mv2.jpg"], "personality": "- IN FOSTER - \nDOB 08/2024. Little gem Jimmy was adopted from us as a puppy and then returned a year later when he was no longer convenient. Playful and fun, Jimmy is looking for a family who will commit to him for good this time. \nJimmy is vaccinated and neutered. His bags are packed and he's ready to go. Can you be his second chance?"},
  {"id": "sdc-joy", "name": "Joy", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years", "ageMonths": 24, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "goodWithKids": false, "photos": ["https://static.wixstatic.com/media/1ababb_5dc67d536d754827ab284b6f9aae9910~mv2.png"], "personality": "- IN FOSTER -\nJoy has been enJOYing her stints at different foster homes for over 2 years now 🥹\nHiking, camping, trekking, beach outings, just chilling…she’s been there and done that 😃\nIt’s now high time for Joy to find her forever home and human(s)🤞🏼\nEspecially as she has been waiting and waiting since a little puppy 🥺\nAt 2.5 years of age, Joy is fully vaccinated and spayed ✔️ \nA small sized girl, she’s way below knee height, weighs under 10 kg and is fully grown ☺️\nWhere are all the small dog lovers?! 😅\nJoy has been in foster homes with other dogs and is currently living with a cat who is her bestie ☺️\nAnd she LOVES meeting people and other dogs on her walks albeit she can get excited 😄\nJoy would be better suited to an adult only household or a home with older children who can respect the need to give a dog its space when required.\nBeing quite food motivated, this makes her eminently trainable 😊\nShe’s fully house trained and walks great on leash like a pro 😇\nWhat’s more, she’s fine being left alone during the day whilst foster mum is at office!\nPlease open your heart and home and let Joy come into your life 🙏🏼\nFill the adoption application and remember to mention Joy 💕"},
  {"id": "sdc-kelly", "name": "Kelly", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 4 months", "ageMonths": 28, "dob": "2.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_adf226f5d8bd47cfa4b2d3da271f2ddf~mv2.jpg"], "personality": "DOB 02/2024. This handsome boy is waiting for his chance to shine in a foster home 🏡 ✨️ 💖 to start his journey to a forever home🤞🏼\nStill very young (born 2/2024), he is fully vaccinated and neutered and waiting for you 🥰\nWith his gorgeous soft coat and huge eyes, that is sure to melt your heart 🥹\nKelly is initially shy, and would really benefit from being in a home with other dogs or a quiet home that will give him a chance. Once he trusts, he just adores to be near to get hugs and kisses 💋 😘 💙\nIf you can foster and help grow his confidence, please contact us to learn more about this beauty!\nStart by filling the adoption / foster application and remember to mention Kelly 💙"},
  {"id": "sdc-lucy", "name": "Lucy", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "young", "ageLabel": "1 year 5 months", "ageMonths": 17, "dob": "1.2025", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "photos": ["https://static.wixstatic.com/media/3c07f5_821c465e43564aecb2b6ef8bc871e9c7~mv2.jpg"], "personality": "DOB 01/2025. Hello there from Lucy! 🎙️ If you thought big ears were cute, look at this girl 🥰 She is flopping them around while running in the dog park like no other dog does 🤠 \nBorn in January 2025, this sweet girl has a character of loving the cuddles, but as soon as the party starts, she is in for the play! 🎠🤹🏼‍♀️ Lucy is also a smart cookie! She learns things so quickly which is why we just know she will excel in a home 🏡 ❤️\nLucy is fully vaccinated and healthy.\nShe is more than ready for a home, are you ready for her? 🐚🐶 Fill in the application online and mention Lucy!"},
  {"id": "sdc-luka", "name": "Luka", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 2 months", "ageMonths": 26, "dob": "4.2024", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_dc82c31433364c8e9a53662d4e67b115~mv2.jpg"], "personality": "DOB 04/2024. Luka came to us as a baby fluff with his siblings and quickly became the chief goofball of the pack.  We don't understand how this fun, loving boy is still waiting for someone to notice how amazing he is Luka makes his own entertainment! Whether he’s zooming around the living room, playing with imaginary friends, or turning a sock into a toy, this guy will keep you laughing.\nFully vaccinated, neutered, certified heart-stealer. What more could you want?"},
  {"id": "sdc-lulu", "name": "Lulu", "gender": "Female", "breed": "Shepherd", "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "6 years", "ageMonths": 72, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/3c07f5_54319790d6294f74afd57dba3e3a8de5~mv2.jpg"], "personality": "- IN TRIAL ADOPTION - \nMeet Lulu, our gorgeous German Shepherd girl with the biggest heart ❤️\nLulu is now in boarding at Paw Parking after spending a few long years at the center.  She's been waiting patiently for a home.  Can you open your heart and home to this deserving girl? 🐾\n- 6 years old, a gentle soul \n- Loves people,  and great with other dogs. \n- loves everyone and deserves love in return\n- Needs a foster home (or better still, a forever home!) ASAP\nLet's give her a chance to feel love, warmth, and a family of her own 💕"},
  {"id": "sdc-maggie", "name": "Maggie", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "goodWithCats": true, "photos": ["https://static.wixstatic.com/media/1ababb_4a7edd2e87f6447fb9fdc030af14a800~mv2.jpg"], "personality": "🐈 CAT FRIENDLY\nLooking for a bouncy and friendly pup that would brighten your day? Look no further 😃. Beautiful Maggie is the right girl for you. She welcomes humans and doggies alike, and she loves cuddles and belly rubs 🥰\nMaggie is still a youngster, born in April 2023 and waiting patiently for her forever family to come along. In the meantime Maggie would love to move to a foster home so she can learn some more.\nShe thrived in her previous foster and we know she will again 😇\nMaggie is fully vaccinated and spayed and ready for adventures with you 🙏\nPlease fill our foster / adoption application and we will arrange you to meet Maggie!"},
  {"id": "sdc-margo", "name": "Margo", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 2 months", "ageMonths": 38, "dob": "4.2023", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_1a86962977c24467b372543ca84b717e~mv2.jpg"], "personality": "Meet Margo 💕\nDOB 04/2023. Now a young adult, this beauty has been growing up in boarding 🥹\nShe, and we, are really hoping she can get into a home soon🤞🏼\nOn the smaller side of medium, Margo is fully vaccinated and spayed.\nIt would be wonderful for her to be able to finally discover the comforts of a home 🙏🏼\nMargo is a friendly girl with people and dogs 🐶\nAnd she has the prettiest eye markings 👀 \nCould you please help this cutie, even if just a 2 week foster offer? 🙏🏼\nIt has been a long wait for Margo!"},
  {"id": "sdc-mark", "name": "Mark", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "4 years", "ageMonths": 48, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "goodWithCats": true, "photos": ["https://static.wixstatic.com/media/3c07f5_ab60451c38ad4d02bae5804e1926bb22~mv2.jpeg"], "personality": "- IN FOSTER - \nMeet the Marvellous Mark!\nWe challenge you to find a sweeter dog on this earth - it’s impossible! Since moving into his first foster home, 4 -year-old Mark hasn't put a single paw wrong. He is the definition of a perfect guest and is officially ready for his forever couch.\n✨ Why Mark is the Gold Standard:\n- The Ultimate Gentleman: A dream on the lead! He never pulls, slows down for you to catch up, and politely stops to let others pass.\n- 100% House Trained: A total pro who never has accidents and sticks perfectly to his outdoor routine.\n- Perfect WFH Partner: Calm, quiet, and independent. He loves his corner and never whines or barks while you work.\n- Cat Friendly: Wonderfully gentle with feline friends; he’s playful but never overbearing.\n- Star Student: A fast learner who already knows \"sit,\" \"stay,\" and \"lay down\" - he even listens without treats!\nMark isn't clingy; he just wants a peaceful place to belong. He is neutered, fully vaccinated, and honestly, the easiest dog you could ever hope to meet. We promise: to meet Mark is to fall in love!\n➡️ Ready to bring the best boy home?"},
  {"id": "sdc-marley", "name": "Marley", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 5 months", "ageMonths": 41, "dob": "2023", "shelterId": "sdc-uaq", "availableFor": "adoption", "neutered": true, "goodWithKids": true, "photos": ["https://static.wixstatic.com/media/1ababb_a646e1797a584cd382156274842f7c24~mv2.jpeg"], "personality": "- IN  TRIAL ADOPTION -\nMarley is a gentle, loving young (born 2023) and house-trained male/medium-sized dog. He’s gentle and sweet 🧸He’s good with children, quiet at home, enthusiastic on walks and fun. He would do great in an active household! 🏃🏽🏕️\nHis favourite treat is chicken yet, despite his excitement, he will take any small treats oh so gently from your hands 🍗🤗 He loves to connect with his human companions and is very attuned to your feelings & will come and provide love whenever he feels you need it! 😍❤️ He is in good health and has had all of his vaccines and has been neutered. \nCan you open your home for this white handsome boy? Fill in the application and mention Marley Jr!"},
  {"id": "sdc-max", "name": "Max", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 8 months", "ageMonths": 32, "dob": "10.2023", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/1ababb_0432a5d21d32415abc2268c218e5d392~mv2.jpg"], "personality": "Meet Max 💙💙\nMax is our sweet and handsome little guy (born 10/2023) who’s really learning and trying to come out of his shell. \nThis shy boy needs time, patience, and a lot of love, but he’s already making amazing progress!😇😇\nMax has previously been in foster care with other SDC alumni, cats and even a rabbit! \nHe’s slowly gained confidence by watching his furry friends around him, unfortunately his time at foster came to end but he was lucky enough to gain a place at Bed and Biscuits boarding, however we really need a home setting for Max to continue his journey 🙏\nInitially, Max prefers to keep a little distance, over time he is happy for his humans to come over for head rubs and, of course, treats—he’s definitely motivated by food! 😄\nMax is 1,5 year old, house trained and enjoys exploring the garden. He’s an easygoing guy who just needs a little more time to fully blossom. With patience, love, and some tasty snacks, Maxi is sure to grow into the gorgeous and loving companion he’s meant to be. 💙🐾\nFill our application today!"},
  {"id": "sdc-maxwell", "name": "Maxwell", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "young", "ageLabel": "1 year 3 months", "ageMonths": 15, "dob": "3.2025", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": false, "photos": ["https://static.wixstatic.com/media/3c07f5_1115436955094b22808f0bc0abe40269~mv2.jpg"], "personality": "- IN FOSTER - \nDOB 03/2025. Say hello to Maxwell, the sweetest little adventurer in his gorgeous brindle coat 😍 This handsome pup is ready to explore the world 🌍🐶 and finally experience what it’s like to have a real home 🏡✨\nHe might be a little shy at first… but don’t be fooled 😏 Once he warms up, Maxwell transforms into a quirky, lovable goofball 🤪 guaranteed to make you laugh and completely steal your heart ❤️ Maxwell lives for playtime with other dogs 🐕🐕, making him the perfect match for a home with a playful pup who wants a bestie 🥰\nHe’s fully vaccinated, will be neutered shortly. Maxwell is thriving in his first foster home and is learning all the house rules. Now, he needs someone to commit to him forever."},
  {"id": "sdc-meydan", "name": "Meydan", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 5 months", "ageMonths": 41, "dob": "1.2023", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "goodWithCats": true, "photos": ["https://static.wixstatic.com/media/3c07f5_4ee88f156eb045fba0322688a4937bc4~mv2.jpg"], "personality": "DOB 01/2023.  After YEARS in foster, poor Meydan finds himself out of a home and back in boarding 😢\nRescued close to 4 years ago, he’d been found roaming the streets obviously abandoned 😔\nThis handsome doggy is approx 5 years of age and is fully vaccinated and neutered ✅ \nWhat’s more, he’s also fully house trained and fine being left alone during the day 😇\nFriendly and social with people, he’s always happy to make new friends 😊\nAnd he has lived with a 🐱 so is cat friendly 😻\nMeydan is an active and energetic dog and is happy to be your running or jogging partner. \nAt the same time, he’s chilled in a home and happy to sofa surf during the day 💤 \nOn leash, he does get overwhelmed when meeting other dogs 🥹\nWhat Meydan seeks is an adult household with dog experienced people."},
  {"id": "sdc-mika", "name": "Mika", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "5 years 6 months", "ageMonths": 66, "dob": "12.2020", "shelterId": "sdc-uaq", "availableFor": "adoption", "photos": ["https://static.wixstatic.com/media/3c07f5_3dbe85a6d3644663ba89293f75c72fd5~mv2.jpg"]},
  {"id": "sdc-miley", "name": "Miley", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "6 years 1 month", "ageMonths": 73, "dob": "5.2020", "shelterId": "sdc-uaq", "availableFor": "adoption", "photos": ["https://static.wixstatic.com/media/3c07f5_8e1a5f364f624cbca0738f73bbf42625~mv2.jpg"]},
  {"id": "sdc-mimi", "name": "Mimi", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 4 months", "ageMonths": 28, "dob": "2.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_6d0639829972400caf30d09de0b77877~mv2.jpg"], "personality": "DOB 02/2024. Have you ever seen a tongue like this? 👅 \nMeet Mimi, our pale desert beauty with unique blue spots on her tongue, a little clue she may have some Chow Chow in her mix 🐾.\nBorn February 2024, Mimi is young, healthy, and ready for her happily‑ever‑after 🏡. Life didn’t give her the fairy tale start 🥺, but she’s bounced back like a champ 💪🏼✨ strong, happy, and full of love to give 💖\nAt first, Mimi’s a little shy (a proper lady never reveals everything on day one 😉). But once she trusts you? Boom 💥 Big personality. Big zoomies. Big cuddles. She’ll have you wondering how you ever lived without her.\nMimi is fully vaccinated and will soon be spayed. Now all she needs is a family or person who sees how truly special she is 💫\n👉🏼 Apply to adopt or foster today and don’t forget to mention Mimi 💕"},
  {"id": "sdc-minnie", "name": "Minnie", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "young", "ageLabel": "1 year 5 months", "ageMonths": 17, "dob": "1.2025", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/3c07f5_8332423c832c422ab2f7f5fdbb1f2fc2~mv2.jpg"], "personality": "- IN FOSTER -\nDOB 01/2025. Meet Minnie the pup with a whole lot of love, laughter, and endless charm! 🐾\nMinnie’s personality lights up every room. She knows what she wants and isn’t shy about letting you know - whether that’s helping you water the plants, joining in on the fun, or curling up for one of her favourite snoozes. She’s currently in a foster home with other dogs and children, so she’s well-socialised and comfortable in a lively household. That said, she’s just as happy in a calm, quiet home where she can enjoy a bit of pampering and plenty of cuddles.\nMinnie is affectionate, full of character, and ready to bring joy to her forever family. If you think this sweet, spirited girl could be the one for you, please fill in our adoption form -Minnie’s ready to make herself at home!"},
  {"id": "sdc-moby", "name": "Moby", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 2 months", "ageMonths": 38, "dob": "4.2023", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/3c07f5_c9f221ce3568432a8d02469480459380~mv2.jpg"], "personality": "DOB 04/2023. This boy is special. We were heartbroken when he went missing while living with a foster. As weeks turned into months, our dreams of finding him started to fade, but we never gave up hope. 20 months after he went missing, we got a call, ''We've found your dog''. \nAn epic story deserves an epic ending. Moby is ready to start his life for real this time. Can you be his happy ever after?"},
  {"id": "sdc-moscow", "name": "Moscow", "gender": "Male", "breed": "mix", "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "6 years", "ageMonths": 72, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "goodWithKids": false, "goodWithCats": false, "photos": ["https://static.wixstatic.com/media/1ababb_22767a7bdaa64d13a9def613025b7758~mv2.png"], "personality": "- IN FOSTER -\nAt 6 years old, our German Shepherd mix Moscow has been waiting a long time for his forever home. He is fully vaccinated and neutered.\nMoscow is an easy dog, and despite his size, you will hardly know he is there - he loves to nap, play with his toys, eat, nap again, and repeat.\nAs a mature dog, Moscow is quite happy to be left by himself for a few hours - in return for arrival home belly rubs of course! \nHe needs someone who has a strong grip as he is a strong on lead, other than that he's 💪 a good boy.\nMoscow is best suited to an adult only house with no cats. \nFill our adoption application and we will arrange for you to meet Moscow."},
  {"id": "sdc-nessy", "name": "Nessy", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "1 year 8 months", "ageMonths": 20, "dob": "10.2024", "shelterId": "sdc-uaq", "availableFor": "both", "neutered": false, "photos": ["https://static.wixstatic.com/media/3c07f5_50a9563b54634c0a9bd9165b807091a9~mv2.jpeg"], "personality": "DOB 10/2024. Nessy has already done an incredible job raising her puppies and being the most wonderful mummy to them 🥰\nShe came into our care with her babies and has lovingly brought them up, giving them confidence, comfort and the very best start in life. \nNow her puppies are getting ready for their forever homes… and it’s finally Nessy’s turn too 😇😇\nThis tiny little lady is honestly everything people are always asking us for. Small, polite, affectionate and easy to have around, Nessy is the perfect mix of sweet and gentle. She absolutely loves cuddles and snuggles and will happily stay close by your side soaking up all the love and attention she can get 🥰\nShe has such a calm, lovely nature and is the kind of dog who makes herself at home in your heart almost instantly.\nNessy is also great on a leash and enjoys getting out and about with her people. Whether it’s a little stroll, curling up beside you on the sofa or following you around the house like your tiny best friend, she is just an all-round superstar 😇\nAfter spending so much time caring for everyone else, we would love for Nessy to finally have a family who will spoil her the way she deserves. She will be spayed soon and is more than ready to start the next chapter of her life in a loving foster or forever home 🙏"},
  {"id": "sdc-nicco", "name": "Nicco", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "5 years", "ageMonths": 60, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_c4ee67dfd0a54f6eb271e17e4f63d0a2~mv2.jpg"], "personality": "Nicco is a wonderful 4-5 year old doggy, who is fully vaccinated and neutered ✅ \nVery friendly with people, Nicco loves to greet whoever he meets! He also loves being around other dogs.\nPlease offer this handsome dude a chance to get ready for the next step in his life journey…a forever home! 🙏 Fill the application to either foster or adopt!"},
  {"id": "sdc-ni", "name": "Ni", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "1 year 6 months", "ageMonths": 18, "dob": "12.2024", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_2894e01864254200afdbe2ad9701ee21~mv2.jpg"], "personality": "DOB 12/2024. This bundle of joy with a smile that will melt your heart 😄✨ This little monkey loves to run, play, and explore outdoors, turning every day into an adventure 🐾🌳 He is a cute white desert mix, those who always surprise you with their shiny and special character 🌟😍\nNiño is ready for his very first home and can’t wait to find a family to share love, laughter, and lots of playtime with 🏡💖 He is neutered, fully vaccinated, and eager to meet the people who will give him a forever home ❤️"},
  {"id": "sdc-oakley", "name": "Oakley", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "4 years 11 months", "ageMonths": 59, "dob": "7.2021", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_320fbe377a5c40fdaf276e6d134678c3~mv2.jpg"], "personality": "DOB 07/2021. If you’re looking for a dog who treats every day like a celebration, meet Oakley. At 4 years old, this handsome Husky has an irresistible \"lust for life\" and a happy bounce that turns every walk into an adventure!\n✨ Why Oakley is Pure Joy:\n- Infectious Enthusiasm: He is friendly with everyone he meets and greets the world with a wagging tail.\n- Steady & Curious: A total pro in the city! He takes traffic and busy crowds in his stride with nothing but healthy curiosity.\n- Husky Spirit: He is a bundle of potential who thrives on activity, engagement, and being part of the action.\n- Home Ready: Neutered, fully vaccinated, and ready to move in today.\n🏠 What Oakley Needs:\n- Active Partner: He needs a committed human for regular walks, runs, and play sessions.\n- A Patient Guide: He’s still learning his leash manners, so he needs a confident leader to show him the ropes.\n- Oakley isn't just looking for a house; he’s looking for a partner to explore the world with. If you have the energy to match his beautiful spirit, he’s ready to meet you!\n➡️ Ready to start the adventure? Apply today:"},
  {"id": "sdc-olive", "name": "Olive", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "adoption", "photos": ["https://static.wixstatic.com/media/3c07f5_60be992d74f846e3939a6229376d170c~mv2.jpeg"], "personality": "- IN TRIAL ADOPTION - \nNEW PUP ON THE BLOCK!\nRecently down from the shelter, we are getting to know this beautiful girl so we can tell you all about her. Check back for more soon!"},
  {"id": "sdc-raven", "name": "Raven", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 3 months", "ageMonths": 27, "dob": "3.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": false, "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/3c07f5_cf938c428047438688755be8013eeeb0~mv2.jpeg"], "personality": "- IN TRIAL ADOPTION - \nDOB 03/2024. Raven isn’t just beautiful with his flowing mane and striking presence 🤩 He’s also incredibly sweet, super cuddly, and full of affection. He’s the kind of dog who will happily curl up next to you, follow you around, and make every day feel a little warmer 🥹❤️\n✨ Fully vaccinated\n✨ Soon to be neutered\n✨ Dog-friendly & social\n✨ Gentle, loving, and easygoing\nHe gets along wonderfully with other dogs and would thrive in a home where she can play, explore, and most importantly, be loved. Whether you’re looking to foster or adopt, Raven is ready to leave his past behind and finally experience what it means to belong 💫"},
  {"id": "sdc-riley", "name": "Riley", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "7 years", "ageMonths": 84, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_2ee605a5dfe94ffa921199020c5f20e9~mv2.jpg"], "personality": "- IN FOSTER - \nSPECIAL SENIOR. Riley Needs a Roommate!\nAlright, folks, Riley is on the hunt for a new place to crash and no, he’s not a college student looking for free WiFi and instant noodles. 🍜💻 This 7-year-old distinguished gentleman (who also happens to be fully vaccinated, neutered, and house-trained ✔️) is just looking for a comfy couch, belly rubs, and a human to call his own. ❤️🐾\nOnce adopted, then returned (seriously, yes! 😤), Riley is now at Bed & Biscuits 🏨🐕, where he’s getting VIP treatment. But let’s be real, he’d rather have a forever home than room service. 🏡✨\nHe’s cool with other dogs 🐕🐩, loves his walks 🚶‍♂️🐾, and is totally fine chilling alone for a few hours while you “work” (aka stare at your laptop and snack). 🍕😆 He’d do best in an adult home or one with older kids who understand that sometimes a guy just wants to nap in peace. 😴\nSo, who’s ready to upgrade their life with this awesome guy? 🤩 If you can foster or adopt, Riley will forever be your biggest fan. 🎉🐶 Let’s get this good boy the home he deserves! ❤️🏡🐾 Fill in the application form for Riley today!"},
  {"id": "sdc-river", "name": "River", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 1 month", "ageMonths": 25, "dob": "5.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/3c07f5_accbdc6943284b7cb476a4cfc90b15f7~mv2.jpg"], "personality": "- IN FOSTER - \nDOB 05/2024 Say hello 👋🏼 to this ray of sunshine with a million dollar smile! 😁\nCurrently in a foster home, this young cutie is always up for fun and games, especially when there’s a tennis ball involved \nThe perfect mix of fun and chill, River will match your energy!\nIf you’d like to get your steps in, he’s game 🏃🏽‍♀️🏃🏽‍♂️ \nIf, on the other hand, you’d like to binge watch your fav show 💻, he’ll be at the ready to curl up on the couch with you 🤗\nA medium sized doggo, River is fully vaccinated and neutered ✔️ \nAlso house trained and fine being left alone for quite some hours 😇\nRiver gets along great with other dogs and is used to frequent play dates and sleepovers with doggo furrends 🐶"},
  {"id": "sdc-roxy", "name": "Roxy", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "7 years 8 months", "ageMonths": 92, "dob": "10.2018", "shelterId": "sdc-uaq", "availableFor": "adoption", "photos": ["https://static.wixstatic.com/media/3c07f5_cf3b146f307e4255910eb599a84ea007~mv2.jpg"]},
  {"id": "sdc-ronny", "name": "Ronny", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "6 years", "ageMonths": 72, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_b3e12344435045ff9180f03dd5d42863~mv2.jpg"], "personality": "- IN FOSTER -\nMeet the very handsome Ronny 😍\nHe is searching for a family to call his own.  Are you searching for a furry friend who's as eager to explore the world as you are? \nLook no further than Ronny! This 5-6 year young desert mix isn't just any dog – he's a ray of sunshine with a smile that'll light up your day! 😁🙆🏻‍♂️\nDespite facing hardships in his past, this gentle soul radiates nothing but love ❤️  His boundless enthusiasm is a reminder to us all to cherish the present moment and find joy in the simple things 🙏🏼💙\nHe's also a loyal companion who's ready to shower you with love and affection. Ronny is fully vaccinated and neutered. 🐶🐾\nSo, what do you say? Ready to open your heart and home to Ronny? Reach out today to learn more about this amazing dog and how you can make him a part of your family. Your new best friend is waiting for you! 🐾❤️"},
  {"id": "sdc-rusty", "name": "Rusty", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 4 months", "ageMonths": 28, "dob": "2.2024", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/3c07f5_40f514cd9e344930ba3e0d565fba77d9~mv2.jpg"]},
  {"id": "sdc-sam", "name": "Sam", "gender": "Male", "breed": "Saluki", "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "5 years", "ageMonths": 60, "dob": null, "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_180a5ba647244568a7b902caf74e58e0~mv2.jpeg"], "personality": "Sam is around 4-5 years of age and is fully vaccinated and neutered ✅ \nA friendly boy, Sam gets along with everyone he meets and is social with people and dogs 🐶 He’s a saluki mix with a massive heart! He loves attention and playing."},
  {"id": "sdc-sandy", "name": "Sandy", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 5 months", "ageMonths": 29, "dob": "1.2024", "shelterId": "sdc-uaq", "availableFor": "both", "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_579f643fde554f3397995b2da90562cc~mv2.jpg"], "personality": "- IN FOSTER - \nDOB 01/2024. This sweet, gentle sould was supposed to be a TNR case given how full we are, but something about her told Auntie Fiona that her time is now. Now is she just needs someone to see what Fiona saw - a sweet, gentle, loving girl who is ready to find her people. Sandy has just been spayed and would love a recovery home. Can you offer her a soft place to land?"},
  {"id": "sdc-sawyer", "name": "Sawyer", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_c0296c3c3b3c4619be96912f78472b2e~mv2.jpeg"], "personality": "- IN FOSTER -\nHappy chap Sawyer is ready to move into a home and looking for a forever family! 🤞🤞🤞\nSurrendered to us by his previous owner, he must be wondering what's going on .... what did I do 🥲 The answer is nothing. From the comforts of a home.... it is tough on these dogs to lose that, but he is resilient and hoping one day he finds this again 🙏🙏\nFor now, he is being cared for by our friends at Hotel Indigo where Sawyer is living, and working, as their Chief Wellbeing Officer!\nHe is an easy going dog that is not about the fuss and more about the love 🐕🧡  he is very active and loves to run, he would really suit an active family or individual 😉\nHe is fully vaccinated and neutered. He loves to be around people 🤗  so his suitcases are packed to move in with you 🧳🏡\nWith his big smile,  he for sure will make every day better ✨ Can you give Sawyer a boost and offer him the chance at a forever home?"},
  {"id": "sdc-saxon", "name": "Saxon", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 2 months", "ageMonths": 38, "dob": "4.2023", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_f4e9d59a114e4774bcdec6dcb3f212d7~mv2.jpg"], "personality": "Introducing Saxon, our Groovy Saxophone Player! 🎷😍\nThis young man (born 4/2023) is already a master at spreading the love with his infectious smile and charming personality 🤩 Despite spending his early days in boarding, he thoroughly blossomed in foster but now finds himself back again through no fault of his own 😪\nThis handsome guy is eager to step out into the world once again and discover the joys of life with his hoomans and some home comforts 🛋️🏡\nWith his upbeat spirit and love for adventure, Saxon is ready to jazz up your life 😁✨\n Saxon is neutered and fully vaccinated. \nAre you ready to welcome Saxon into your home and be serenaded by his sweet melodies and cuddles? 🎵❤️ Let's make some beautiful music together and get Saxona home... even temporarily! 🏡✨ Fill our application today and mention Saxon!"},
  {"id": "sdc-seany", "name": "Seany", "gender": "Male", "breed": "Husky", "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_8332150eb1ff43d89fd6d4bfafb35d5a~mv2.jpg"], "personality": "- IN FOSTER -\nOur very happy boy Seany 😀 who loves posing for the ladies for pictures 😀 \nHe loves to greet everyone that crosses paths with him with a smile,  and he loves the attention to sneak a chance at a strokes our some extra cuddles 🌹😏 A true casanova! 🥰\nHe needs a foster home, even for a few weeks to experience a home once again. Seany was once a beloved family pet, now spends his life wondering what happened 😔\nSeany is ready to make your life even more amazing, so  can you help to make his also? 🙏\nWith his beautiful markings, gorgeous coat, and wide smile, he is ready to shine in a home 🏡 😀 ✨️ ❤️ \nAt four years old, he is an active and healthy boy, fully vaccinated and neutered.  He would do great in a home with humans or furry friends alike 🐕 \nWould you like to meet Seany? Could you help giving him a foster?\nReach out to us! 💬\nOr fill the foster application and we'll contact you!"},
  {"id": "sdc-shaggy", "name": "Shaggy", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "senior", "ageLabel": "10 years 6 months", "ageMonths": 126, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/3c07f5_e2fe6b6787434b50b33c0f96d61c677d~mv2.jpeg"], "personality": "- IN FOSTER - \nSPECIAL SENIOR. \nForever home for an old boy 🙏\nMeet our lovely ole boy Shaggy.\nAfter years and years at the Center, Shaggy got his chance to move to boarding and finally a foster home ❤️\nShaggy is 10.5 years of age. He is a quiet and shy boy but loves the company of humans 🤗\nHe also loves being around other dogs, and has thrived in foster with his furry step brother or alternatively alone he's happy out 😇\nWhy a senior doggy you may well ask?\nBecause they’re relaxed and content and dont ask for alot 😇😇😇\nPlease open your heart and home to a senior. You really won't regret it 🙏"},
  {"id": "sdc-skye", "name": "Skye", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 4 months", "ageMonths": 28, "dob": "2.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_89c80c4c72fd47d7bbc734d5c8ebd99d~mv2.png"], "personality": "Curly tails aren’t the most common we see… but Sky isn’t your common dog.\nThis young desert beauty (born 2/2024) carries her tail like a little Basenji, and her gentle soul is just as special. Sky is a quiet girl with soft eyes, a real sweetheart💞\nShe may be shy at first, but once she warms up, you’ll meet the sweetest, calmest companion — a gentle observer who loves soft walks, cozy cuddles, and peaceful car rides with the breeze in her fur 🚗🌬️💕.\nPolite on the leash, curious but never chaotic 🧸🎀, and always content simply being by your side. Sky is the perfect blend of serenity and charm 🐾💛.\nShe’s spayed, fully vaccinated, and patiently waiting for a cozy corner and a human to call her own 🐾💛\n📩 Fill the application to foster or adopt Sky, and our team will be in touch!"},
  {"id": "sdc-snowy", "name": "Snowy", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "4 years 5 months", "ageMonths": 53, "dob": "1.2022", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "goodWithKids": false, "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/1ababb_fbe7d8f73df54c02a4a72514569cf636~mv2.jpeg"], "personality": "Lovely Snowy 🤍 has been waiting for her forever home for quite some time now.  She is still young (born 1/2022), fully vaccinated and spayed.\nTimid by nature, she will approach new people with caution but with curiosity. Once she trusts someone, she becomes an unconditional friend and very loyal companion 😇\nA calm girl and undemanding, she would be happy to have her little cozy corner in a quiet home 😇. \nShe loves her walks and is also good with other dogs. She would thrive better in an adult only home or older children, as she gets nervous easy. She really deserves a chance 🙏🙏🙏\nGoing from foster to foster, and now she's back in boarding 😩 poor Snowy dosen't know what she's doing wrong.\nPlease fill out the foster or adoption application if you would like to meet Snowy 🥰"},
  {"id": "sdc-sox", "name": "Sox", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "senior", "ageLabel": "12 years", "ageMonths": 144, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/3c07f5_59a2d2c8e6a04069873842578a3fcc67~mv2.jpg"], "personality": "- IN FOSTER - \nSPECIAL SENIOR\nOur golden Sox is hoping to find his forever home and hooman(s)🤞🏼\nThis mature gentleman is nearly 12 years young 🧿 \nA lovely old soul, Sox is absolutely wonderful with people; big and small ☺️\nBeing in foster in homes with babies and thereafter with school going children, he’s well used to the hustle and bustle of a busy household and takes it all in his stride 😊\nCurrently in foster in a home where he’s alone during the day, Sox is equally content in his own company 😊\nVilla or apartment, Sox has lived in both and is just happy to have a comfy bed to rest his head 🥹\nAnd of course a couple of walks a day to stretch his legs and do his business 😇\nA great fit into any home, Sox is hoping against hope that his next move will be to his retirement home🤞🏼🥹\nAre you the one to make this old boy’s dream come true?! 🙏🏼\nFill the adoption application and remember to mention Sox 💙"},
  {"id": "sdc-speckles", "name": "Speckles", "gender": "Male", "breed": "Shepherd", "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "6 years 5 months", "ageMonths": 77, "dob": "2020", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "neutered": true, "goodWithDogs": true, "photos": ["https://static.wixstatic.com/media/1ababb_b8584cddf85948009282d876725fb948~mv2.jpeg"], "personality": "Stunning Speckles, born in 2020, is a high energy, super trainable, Dutch shepherd mix. \nEnergetic and playful by nature, Speckles would suit a household with an active lifestyle and given his personality, a home where he can be mentally and physically engaged!\nSpeckles will need training however is a very clever learner. And so handsome as well!\nLook at his beautiful brindle coat 🥰\nFriendly with dogs and people this boy is neutered and fully vaccinated."},
  {"id": "sdc-stephan", "name": "Stephan", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 2 months", "ageMonths": 38, "dob": "4.2023", "shelterId": "sdc-uaq", "availableFor": "adoption", "vaccinated": true, "photos": ["https://static.wixstatic.com/media/3c07f5_4716f80f6575440aa9c16b8664b8d933~mv2.jpg"], "personality": "DOB 04/2023. Our gorgeous boy Stephan is looking for a home 🏡. He was born in April 2023 and he’s quite gentle and timid by nature. He would be a lovely quiet pet in a small family unit. Stephan would like to have a human buddy and someone to give him love and affection. In return he will be the most devoted furry friends 😇\nHe is fully vaccinated and ready for the next chapter of his life. \nPlease fill out our application or message us for a private meeting with him!"},
  {"id": "sdc-sunny", "name": "Sunny", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years", "ageMonths": 36, "dob": "6.2023", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "goodWithKids": true, "goodWithCats": true, "photos": ["https://static.wixstatic.com/media/1ababb_daa38e07267c4beb8af23d0a8380ab1e~mv2.jpg"], "personality": "DOB 06/2023. Sweet Sunny ☀️\nSome dogs are born with a light inside them and Sunny is one of those souls 💡💛\nHe was found one morning, chained outside a vet clinic, left behind without explanation. We don’t know how long he waited, or how confused and scared he must have been. But what we do know is that Sunny never let it harden his heart. He’s as kind, gentle, and loving as ever 🥹🐾\nBorn in 2023, he is a young adult, neutered, and fully vaccinated, Sunny is looking for a foster home. A warm spot on the couch, a hand to hold, someone to remind him that he matters 🏡✨\nHe’s amazing with children, gentle with cats, and absolutely adores people 🤩 He’s doing great with his toilet training and walks beautifully on the leash. All he wants is to be near you, soaking up the comfort he’s been missing 💛\nSunny has been through so much, yet he still greets the world with a wagging tail and hope in his eyes. If you can give him even a few weeks of love, it would mean the world to him and to us.\n📩 Fill out the form and mention Sunny"},
  {"id": "sdc-sweetie", "name": "Sweetie", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 2 months", "ageMonths": 38, "dob": "4.2023", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": false, "photos": ["https://static.wixstatic.com/media/3c07f5_54f83e9ad6164622912eeead464a3850~mv2.jpg"], "personality": "- IN FOSTER - \nDOB 04/2023. Beautiful Sweetie recently got her golden opportunity to leave the center, and she has embraced home life with all four paws! This gentle soul is looking for a patient, loving family to call her own.\nQuick Facts:\nVibe: Extremely gentle and likes to take life at a slower, quiet pace.\nStatus: Fully vaccinated and will be spayed soon.\nTraining: House-trained and very polite.\nPersonality: A little shy at first, but super sweet and affectionate.\nWhy She’s The One:\nNeighborhood Explorer: She truly enjoys her daily walks, nice food, and exploring all the amazing new smells around her.\nProfessional Napper: Sweetie likes nothing more than a good snooze on the couch after her adventures.\nGentle Soul: She is an extremely gentle dog who would thrive in a quiet, peaceful environment.\nTenfold Love: While she may be shy initially, she is an affectionate doggy who will return your love ten times over.\nThe Dream: She is looking for a patient and loving family, just like her amazing foster home."},
  {"id": "sdc-tallulah", "name": "Tallulah", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 3 months", "ageMonths": 39, "dob": "3.2023", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": false, "photos": ["https://static.wixstatic.com/media/3c07f5_3c6238086e42485eae2a5375b23c0509~mv2.jpg"], "personality": "- IN FOSTER - \nDOB 03/2023. Mama duties: COMPLETE. Now it’s Tallulah’s turn to be the baby 💅🐾💕 Meet Tallulah: 3 years young, a gorgeous small-to-medium desert mix, and recent supermom to a litter of ridiculously adorable pups 🥺🐶✨ She’s done the hard work, raised her babies like a champ… and now she’s ready for something she’s never truly had:\nA home that’s all about her 💛\nAnd don’t worry, she’s not here for empty nest syndrome. Oh no 😄 Tallulah is ready to trade in motherhood for:\n🐾 A cozy nest of her own (finally!)\n🐶 Or even some new furry siblings to boss around lovingly 😉\n🛋️ Chill time, cuddles, and well-deserved pampering\n🌟 A life where she gets to be spoiled for once\nShe’s the full package:\n✨ Sweet, gentle, and resilient\n✨ The perfect size for literally any home\n✨ Recently retired mama, now accepting applications as “your baby”\n✅ Fully vaccinated\n✅ Soon to be spayed \n✅ Overflowing with love and ready for her next chapter 💕\nAfter everything she’s done, don’t you think it’s her turn to shine? 🥹✨\nLet’s find Tallulah the forever home she’s been waiting for 💛"},
  {"id": "sdc-theo", "name": "Theo", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years 2 months", "ageMonths": 26, "dob": "4.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_d6020e27b99246bfbc11444e5c0cfcd4~mv2.png"], "personality": "Allow me to introduce myself, I’m Theo (short for Theodore 😅)\nI’m waiting and hoping to find my own home and hoomans soon🤞🏼\nI have it on good authority that I’m a handsome lad, if I do say so myself 😉\nI do think my expressive eyebrows and masked face might have something to do with it.\nI’m still young (born 4/2024) and am fully vaccinated & neutered ✔️ \nAll I need is a chance to show what a good boi I am 🥹\nAnd while I am enjoying spending time with my siblings and other puppies in boarding, nothing beats being in a home 🤗\nI'd love to meet you soon so please fill the adopt/foster application today!"},
  {"id": "sdc-thor", "name": "Thor", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "7 years 4 months", "ageMonths": 88, "dob": "2.2019", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_8459a8dfd30140cda15f98c683185f61~mv2.jpg"], "personality": "- IN FOSTER - \nDOB 02/2019. Thor knows how to be a great walking partner. He doesn't pull, is not reactive, and is just out to enjoy the sniffs and fresh air. Recently moved to boarding from the shelter, we have yet to see a reason Thor could have given his family for giving him up, but sadly, for most of our dogs, its nothing they have done.  A true gent, this friendly boy is fully vaccinated, neutered, and ready to have his second chance at a forever home."},
  {"id": "sdc-tiny", "name": "Tiny", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 4 months", "ageMonths": 40, "dob": "2.2023", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_e82ed27bc36440878cbf968edc90a3a9~mv2.png"], "personality": "DOB 02/2023. Meet (not so) Tiny 😅\nThis handsome lad with his leaf 🍃 like ears is having a great time hanging out with his fur buddies in boarding, but nothing can match upto the comforts of a home 🥹\nTiny was lucky to be born (2/2023) within the safety of the shelter, but he is now grown to his full size and has never known a home, apart from some short spells in foster, which he loved and thrived 😔\nWe would love for him to enjoy a bed and his very own toys in the comforts of love ❤️\nTiny is medium sized, fully vaccinated and neutered ✔️ \nA shy yet friendly boy, he’s equally happy in the company of hoomans as he is with other doggies 😊\nOh and he does love posing for the camera!\nAs you can see from his recent photoshoot 😂\nWill you make Tiny’s wish of a home come true? 🙏🏼\nFill our application now, Tiny is waiting!"},
  {"id": "sdc-toby", "name": "Toby", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years 4 months", "ageMonths": 40, "dob": "2.2023", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_c86155aac256486e85a6d6151b75dc3b~mv2.jpg"], "personality": "DOB 02/2023. Say hello to Toby, the sweetest soul you'll ever meet 😇💙 Toby has been waiting for a home for a long time in boarding! He was often overlooked except for a few short stints in foster care. But in a home, he truly shines and blossoms 🌸🌸🌸\nWhy has he been overlooked? 🤷🏻‍♀️ Hard to say, but one thing is certain—whoever is lucky enough to give him a chance will be greeted with endless love and excitement, and Toby will make sure every day feels like the best day 😇🥰\nToby is fully vaccinated, neutered, and as friendly and social as they come 🐕 He loves to be around people and is ready to give his heart.\nCould Toby be the companion you've been waiting for? If so, please visit our website and fill out the form to help make Toby's dreams of a home come true ❤️\nEven for a few weeks 🤞🤞"},
  {"id": "sdc-toby-2", "name": "Toby", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "goodWithKids": true, "photos": ["https://static.wixstatic.com/media/1ababb_741f19c6dede4a5cb4da16c2242bc3eb~mv2.jpg"], "personality": "- IN FOSTER -\nSPECIAL SENIOR.\nToby is easy going, walks nicely on the leash and likes to have many naps on the couch 😴🩵 … preferably with you next to him!❤️\nToby is good with kids and not bothered by cats. Adores company of people, but also good on his own for a few hours to catch up on his beauty sleep 😴 \nAre you willing to give this mature boy for his furever home? Send us a message or fill in the form and mention Toby 🐕"},
  {"id": "sdc-truffle", "name": "Truffle", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "young", "ageLabel": "10 months", "ageMonths": 10, "dob": "8.2025", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/3c07f5_314e3b2da10f4311ab5ee991c8ef9d4c~mv2.jpeg"], "personality": "- IN FOSTER - \nDOB 08/2025. This beautiful floof was rescued pregnant and had two beautiful puppies soon after. She didn't get a chance to enjoy her own puppy months but now she has raised her pups, its her turn to find happiness.\nPetite in size, sweet, gentle, loving and playful, Truffle is the complete package!"},
  {"id": "sdc-vergo", "name": "Vergo", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years", "ageMonths": 36, "dob": "6.2023", "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/1ababb_a95aa131bd9343cf97e8c09ab80ab876~mv2.jpeg"], "personality": "- IN FOSTER -\nThis is Vergo, the bundle of joy that's stealing hearts left and right! 🐾✨ This adorable white youngster (born 6/2023) is on the hunt for his forever foster or adoption home! 🏡❤️\nVergo was a bit shy when he arrived with us, but now he is a walking, wagging happiness machine! 😁 His infectious energy and heart-melting cuteness are sure to brighten up your days, turning the ordinary into the extraordinary🌟✨ \nWhether it's playtime in the park, snuggles on the couch, or learning new tricks, Vergo is your go-to furry friend for all things happy and heartwarming! 🎉💖\nThis little ball of sunshine is looking for a family to call his own, filled with love, laughter, and lots of belly rubs. 🏡⚽️ Are you ready to open your heart and home to Vergo's wag-tastic charm? Don't wait, fill the application today!"},
  {"id": "sdc-vespa", "name": "Vespa", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "2 years", "ageMonths": 24, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_45b54d33b9ac40c1a8f1629a173fb5da~mv2.jpg"], "personality": "- IN FOSTER - \nVespa Is Ready for Her Adoption Family 🛵❤️\nVespa is no longer searching for a foster,  she’s thriving in her current foster home and showing everyone just how wonderful she truly is 🌟🐾  She’s blossomed into a confident, playful sweetheart who now gallops joyfully through the dog park (see her video — she’s a rocket!) 🐕💨💛\nVespa is a naturally gentle, curious girl who once needed time to warm up to the world 🌍💗 She’s affectionate, loyal, and eager to keep growing ✨\nAt just over 2 years old, she’s spayed and fully vaccinated 🏡💞 Her soft ears, expressive eyes, and tender personality make her truly unforgettable 😍👀💖\n She’s ready now to settle into a forever home of her own 🥹🏠\nIf you think Vespa could be the one for you, please complete the adoption form"},
  {"id": "sdc-vice", "name": "Vice", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_0a9e1cebaf2e47b498f7f055f2104283~mv2.jpg"], "personality": "Meet Vice - a gentle soul with a heart of gold.\nBorn in June 2023, Vice has spent his entire young life in boarding, quietly waiting for the family that will finally see him for the loving pup he is. Though shy at first, once he feels safe, Vice transforms into a sweetheart who loves cuddles and dreaming of ice cream dates 🍦💙.\nWith a calm and patient nature, Vice would thrive in a family with children, where his gentle spirit can truly blossom 🌻. He’s already neutered and fully vaccinated, ready and eager to start his forever life filled with love and belonging.\nIf you’re looking for a quiet, kind companion who just needs a little time and lots of heart, Vice is waiting for you. Open your home and heart to this wonderful boy and watch him shine ✨ \nSend us a message to learn more about fostering or adopting this wonderful pup! Together, we can give Vice the loving home he deserves ❤️  Please fill our application today to meet lovely Vice!"},
  {"id": "sdc-vimto", "name": "Vimto", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "3 years", "ageMonths": 36, "dob": "6.2023", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_d146b03ba814429598d49ba898d46294~mv2.jpg"], "personality": "- IN FOSTER - \nVimto has a soft soul and eyes that quietly ask for love.\nA young adult (born 6/2023), Vimto has spent his whole life in boarding with his siblings—but he’s still waiting for his first real chance at a home 🏡\nHe may be shy at first, but give him a little time and you’ll see the sweetest, most loving boy emerge. He’s gentle, calm for his age, and has a playful spark that lights up once he feels safe 🐾💛\nNeutered, vaccinated, and ready to go, Vimto is looking for a patient foster or forever family to show him what it means to belong. His quiet presence, soft nature, and tender heart make him a truly special companion.\nIf you’re ready to meet a dog who just needs someone to believe in him—Vimto is waiting. 🤍\nStart by filling our application to adopt or foster and we will arrange for you to meet Vimto!"},
  {"id": "sdc-vinnie", "name": "Vinnie", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "goodWithKids": true, "photos": ["https://static.wixstatic.com/media/1ababb_443aab96d0a547879d8467f2a0589b75~mv2.png"], "personality": "Meet Vinnie — the cheerful, playful spirit who’s ready for his forever home.\nBorn in June 2023, Vinnie is a desert mix with a whole lot of heart ❤️. Lucky enough to have spent time in foster care, he’s already learned the joys of a loving home and can’t wait to make yours even brighter.\nVinnie’s friendly nature shines through in everything he does. He adores children and thrives in a family environment, where his goofy antics and endless playfulness bring laughter and love ⚽️⛹🏽‍♂️. Gentle and affectionate, he’s ready to be your kids’ new best friend and a loyal companion for life.\nFully vaccinated and neutered, Vinnie is prepared and eager to move into his forever home. Don’t miss the chance to welcome this happy boy into your heart and home 🏡🌟."},
  {"id": "sdc-violet", "name": "Violet", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "1 year 6 months", "ageMonths": 18, "dob": "12.2024", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/3c07f5_20bbbb6cbd114b0dbf7a1ceacffdc841~mv2.jpg"], "personality": "DOB 12/2024. This little beauty is now ready to leave boarding and get back to living her life 😇\nShe is an extremely friendly, playful, and happy girl,  as she should be 💕\nShe is super social with people, dogs and everyone she meets  ☺️  She is an absolute joy to be around 🥰\nGiven her beautiful temperament, Violet would fit into any home 😊 \nViolet is fully vaccinated and spayed.\nPlease help by opening your heart and home to foster her now ❤️"},
  {"id": "sdc-wilma", "name": "Wilma", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "4 years", "ageMonths": 48, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "goodWithCats": false, "photos": ["https://static.wixstatic.com/media/1ababb_ba8b26a786f54fd4813e687e258b0e71~mv2.jpg"], "personality": "Wilma is one of those dogs who makes life feel warmer 💛\nShe wakes up happy, loves being around people, and finds excitement in the simplest things, whether it’s a walk, a run, a puzzle toy, a piece of watermelon, or a tennis ball (which usually has a very short life expectancy 😅).\nAt 4 years old, Wilma is playful, affectionate, clever, and wonderfully full of personality. She’s fully house trained, settles beautifully into routines, doesn’t bark unnecessarily, and is very easy to train thanks to her love of treats and human attention.\nShe’s always happy to head out for a walk and also makes a brilliant jogging companion 🐾\nWilma enjoys enrichment games, learns quickly, and genuinely just loves being included in everyday life. Whether you’re out exploring or relaxing at home, she’s happiest simply being near her people.\nWilma would do best in a home without cats, and while she can sometimes get a little defensive when passing certain dogs on walks, she is very manageable and strongly people-focused.\nShe’s such a lovely companion and so ready for a foster or forever home of her own.\nOffer Wilma a foster or forever home:\nApply online and our team will be in touch."},
  {"id": "sdc-winnie", "name": "Winnie", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "6 years", "ageMonths": 72, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "neutered": true, "photos": ["https://static.wixstatic.com/media/1ababb_c3b242ceb4a845749d4599ce40d03a5a~mv2.jpg"], "personality": "- IN FOSTER - \nMeet Winnie – Our gentle, easygoing girl 💛🐾\nWinnie has spent years at the shelter, followed by a few months in boarding as part of our Boster program. She’s now enjoying the comfort of a lovely foster home, where she’s thriving with the care and attention she truly deserves.💖\nAt 6 years old, Winnie is vaccinated, spayed, and ready to start the next chapter of her life—with a forever family to call her own.🏡\nThis medium-sized sweetheart is friendly, calm, and wonderfully low-maintenance. She loves belly rubs, relaxing on the balcony, and simply being close to the people she trusts. Winnie is very much a homely dog: clean, well-behaved, and an excellent sleeper 😴. She’s the perfect companion for a peaceful home.🏠\nIf you’re looking for a loyal, gentle soul to share your days with, Winnie might just be the one. 💫\nFill out our adoption form and don’t forget to mention Winnie!"},
  {"id": "sdc-whiskey", "name": "Whiskey", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "6 years", "ageMonths": 72, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "photos": ["https://static.wixstatic.com/media/1ababb_4c9b6f218a78491ab3ebb02b9b4fd847~mv2.jpg"], "personality": "SPECIAL SENIORS. These two senior dogs find themselves back with us again after all these years! The situation is extremely sad for everyone, all round 😪  Whiskey & Quinn, were surrendered after being adopted together 6 years ago. They have been in and out of boarding and foster homes ever since, almost 2 years and counting 😪\nThese two are like two peas in a pod, very close and dependant on each other and are simply the best boys 😇💙  \nThis would be an extremely easy foster to take both, as they keep each other company and being two older dogs, sleep alot!"},
  {"id": "sdc-winston", "name": "Winston", "gender": "Male", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": null, "ageMonths": null, "dob": null, "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "photos": ["https://static.wixstatic.com/media/3c07f5_528c1d073fd44628aaa7877e19503e38~mv2.jpeg"], "personality": "- IN FOSTER - \nWinston is one of the lucky dogs to recently leave the shelter to join our 'boster' programme in Dubai at Bed & Biscuits, where we can get to know him better to enable us to find his perfect match.\nWhat we do know is that Winston is fully vaccinated."},
  {"id": "sdc-wurly", "name": "Wurly", "gender": "Female", "breed": null, "size": null, "sizeLabel": null, "ageGroup": "adult", "ageLabel": "6 years 3 months", "ageMonths": 75, "dob": "3.2020", "shelterId": "sdc-uaq", "availableFor": "both", "vaccinated": true, "photos": ["https://static.wixstatic.com/media/3c07f5_2fdd5638c15f4758b5c93b14468b3ff1~mv2.jpg"], "personality": "DOB 03/2020. After a long wait at the shelter, Wurly has finally caught her big break! This beautiful lady has officially moved into our ‘Boster’ programme at Bed & Biscuits a vital step where sponsors help cover boarding so pups like Wurly can decompress and be seen.\n✨ Why Wurly is a True Catch:\n- Friendly & Fun: She is a playful, social girl who truly enjoys the company of both people and other dogs.\n- A Heart of Gold: At 6 years old, Wurly has a mature, loving soul. She’s at that perfect age where she’s settled but still has plenty of pep in her step.\n- Blooming Daily: After so long in the shelter, she is working hard on adjusting to her new world. Every day, she reveals more of her sweet personality!\n- Ready to Go: Wurly is fully vaccinated, and waiting for the sofa she’s dreamed of for years.\n🏠 Wurly’s Dream Home:\nWurly is looking for a family that understands that the best things in life are worth waiting for. Any family lucky enough to welcome her will be gaining a loyal, grateful companion who truly appreciates every kind word.\n➡️ Could you be the one to give Wurly her happy ever after? Apply to foster or adopt!"},
];
